import { GoogleGenAI } from "@google/genai";
import { Company } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCompany = async (company: Company) => {
  try {
    const prompt = `Analise os seguintes dados da empresa e forneça um resumo executivo com: 
    1. Perfil de Mercado
    2. Potencial de Risco (baseado no capital social e CNAE)
    3. Sugestão de abordagem comercial.

    Dados: ${JSON.stringify(company)}`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: "Você é um analista sênior de crédito e inteligência de mercado especializado em empresas brasileiras."
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    return "Não foi possível gerar a análise no momento.";
  }
};

export const generateMarketTrends = async (companies: Company[]) => {
  try {
    const summary = companies.map(c => `${c.tradeName} (${c.cnaeDescription}) em ${c.address.city}`).join(", ");
    const prompt = `Com base nesta lista de empresas: ${summary}. Gere 3 tendências rápidas de mercado para este grupo.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt
    });

    return response.text;
  } catch (error) {
    return "Tendências não disponíveis.";
  }
};

