import React, { useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell 
} from 'recharts';
import { Company } from '../types';
import { Building2, Users, CreditCard, TrendingUp } from 'lucide-react';

interface DashboardProps {
  companies: Company[];
}

const Dashboard: React.FC<DashboardProps> = ({ companies }) => {
  const stats = useMemo(() => {
    const byState = companies.reduce((acc, curr) => {
      acc[curr.address.state] = (acc[curr.address.state] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const chartDataByState = Object.entries(byState).map(([name, value]) => ({ name, value }));

    const totalCapital = companies.reduce((acc, curr) => acc + curr.capital, 0);
    const activeCount = companies.filter(c => c.status === 'Ativa').length;
    const avgPartners = companies.reduce((acc, curr) => acc + curr.partners.length, 0) / companies.length;

    const byStatus = [
      { name: 'Ativas', value: activeCount, color: '#10b981' },
      { name: 'Outras', value: companies.length - activeCount, color: '#ef4444' }
    ];

    return { chartDataByState, totalCapital, activeCount, avgPartners, byStatus };
  }, [companies]);

  const StatCard = ({ icon: Icon, label, value, color }: any) => (
    <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-200">
      <div className="flex items-center gap-4">
        <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white ${color}`}>
          <Icon size={24} />
        </div>
        <div>
          <p className="text-slate-500 text-sm font-medium">{label}</p>
          <p className="text-2xl font-bold text-slate-900">{value}</p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard 
          icon={Building2} 
          label="Total Empresas" 
          value={companies.length} 
          color="bg-indigo-500" 
        />
        <StatCard 
          icon={TrendingUp} 
          label="Taxa de Atividade" 
          value={`${((stats.activeCount / companies.length) * 100).toFixed(0)}%`} 
          color="bg-emerald-500" 
        />
        <StatCard 
          icon={CreditCard} 
          label="Capital Total" 
          value={new Intl.NumberFormat('pt-BR', { notation: 'compact', style: 'currency', currency: 'BRL' }).format(stats.totalCapital)} 
          color="bg-blue-500" 
        />
        <StatCard 
          icon={Users} 
          label="Média Sócios" 
          value={stats.avgPartners.toFixed(1)} 
          color="bg-violet-500" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-900 mb-6">Empresas por Estado</h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.chartDataByState}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} />
                <Tooltip 
                  cursor={{fill: '#f1f5f9'}}
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
                <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-900 mb-6">Situação Cadastral</h3>
          <div className="h-64 flex items-center justify-center">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.byStatus}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {stats.byStatus.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                   contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}}
                />
              </PieChart>
            </ResponsiveContainer>
            <div className="absolute flex flex-col items-center">
              <span className="text-2xl font-bold">{companies.length}</span>
              <span className="text-slate-400 text-xs font-medium">Empresas</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import CompanyCard from './components/CompanyCard';
import Dashboard from './components/Dashboard';
import { Company, ViewType } from './types';
import { MOCK_COMPANIES } from './mockData';
import { Search, SlidersHorizontal, Info, Sparkles, X, Phone, Mail, MapPin, Building, History, Globe } from 'lucide-react';
import { analyzeCompany } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCompany, setSelectedCompany] = useState<Company | null>(null);
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const filteredCompanies = useMemo(() => {
    return MOCK_COMPANIES.filter(c => 
      c.tradeName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.legalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.cnpj.includes(searchTerm)
    );
  }, [searchTerm]);

  const handleCompanyClick = (company: Company) => {
    setSelectedCompany(company);
    setAiAnalysis(null);
  };

  const runAiAnalysis = async () => {
    if (!selectedCompany) return;
    setIsAnalyzing(true);
    const result = await analyzeCompany(selectedCompany);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex">
      <Sidebar 
        currentView={currentView} 
        setView={setView} 
        isOpen={isSidebarOpen} 
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
      />

      <main className="flex-1 lg:ml-64 p-4 lg:p-8">
        {/* Header Section */}
        <header className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
          <div>
            <h2 className="text-2xl lg:text-3xl font-bold text-slate-900">
              {currentView === 'dashboard' && 'Visão Estratégica'}
              {currentView === 'search' && 'Consulta de Empresas'}
              {currentView === 'analytics' && 'Insights com IA'}
              {currentView === 'favorites' && 'Suas Empresas Salvas'}
              {currentView === 'settings' && 'Preferências do Sistema'}
            </h2>
            <p className="text-slate-500 mt-1">
              {currentView === 'dashboard' && 'Acompanhe as métricas em tempo real da sua base de dados.'}
              {currentView === 'search' && 'Explore nossa base de dados com filtros inteligentes.'}
              {currentView === 'analytics' && 'Deixe nossa inteligência artificial descobrir padrões ocultos.'}
            </p>
          </div>

          <div className="flex items-center gap-3">
            <div className="relative flex-1 md:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="CNPJ, Razão Social ou Nome..."
                className="w-full pl-10 pr-4 py-2.5 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all shadow-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <button className="p-2.5 bg-white border border-slate-200 text-slate-600 rounded-xl hover:bg-slate-50 transition-colors shadow-sm">
              <SlidersHorizontal size={20} />
