          </div>
        </header>

        {/* Content Section */}
        <div className="space-y-8">
          {currentView === 'dashboard' && <Dashboard companies={MOCK_COMPANIES} />}

          {(currentView === 'search' || currentView === 'dashboard') && (
            <section>
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-lg font-bold text-slate-900">Empresas Encontradas ({filteredCompanies.length})</h3>
                <div className="text-sm text-indigo-600 font-medium cursor-pointer hover:underline flex items-center gap-1">
                  Ver todas <Info size={14} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                {filteredCompanies.map(company => (
                  <CompanyCard 
                    key={company.id} 
                    company={company} 
                    onClick={handleCompanyClick} 
                  />
                ))}
                {filteredCompanies.length === 0 && (
                  <div className="col-span-full py-20 text-center">
                    <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-400">
