import { GoogleGenAI } from "@google/genai";
import { Company } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Realiza uma busca profunda na web sobre um CNPJ específico
 * Simula o 'scraping' de dados públicos, Reclame Aqui e notícias.
 */
export const deepSearchCNPJ = async (cnpj: string) => {
  try {
    const prompt = `Realize uma investigação detalhada sobre a empresa com CNPJ ${cnpj}. 
    Procure por:
    1. Dados públicos e situação cadastral atualizada.
    2. Reputação e reclamações recentes no Reclame Aqui ou órgãos similares.
    3. Presença digital e redes sociais.
    4. Notícias recentes ou processos públicos relevantes.

    Apresente um resumo executivo estruturado.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um agente de inteligência corporativa. Sua tarefa é compilar um dossiê atualizado baseado em fontes da web."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Deep Search Error:", error);
    throw error;
  }
};

export const analyzeCompany = async (company: Company) => {
  try {
    const prompt = `Analise os dados: ${JSON.stringify(company)}. Forneça insights sobre saúde financeira e competitividade.`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    return "Erro na análise.";
  }
};

