import { GoogleGenAI, Type } from "@google/genai";
import { Company } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Dados Públicos Profunda
 * Vascunha Google, Reclame Aqui e Portais Indexados
 */
export const fetchPublicDataReport = async (cnpj: string, companyName: string) => {
  try {
    const prompt = `Realize uma consulta profunda de DADOS PÚBLICOS sobre a empresa ${companyName} (CNPJ: ${cnpj}).

    FONTES OBRIGATÓRIAS DE PESQUISA:
    1. Reclame Aqui (reputação, nota, principais queixas).
    2. Google News (notícias recentes, fusões, escândalos ou premiações).
    3. Portais de Transparência e Diário Oficial.
    4. Redes Sociais e LinkedIn (presença e engajamento).

    ESTRUTURA DO RELATÓRIO:
    - AVALIAÇÃO FINAL: Atribua uma nota de 0.0 a 10.0 baseada na confiança e reputação.
    - RESUMO EXECUTIVO: Visão geral da saúde pública da marca.
    - RECLAME AQUI: Detalhamento da situação no portal.
    - CLIPPING DE NOTÍCIAS: O que o Google diz sobre ela agora.
    - ANÁLISE DE RISCO: Baixo, Médio ou Alto para novos negócios.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um analista sênior de compliance e reputação corporativa. Seu tom é profissional, direto e imparcial."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Deep Public Search Error:", error);
    throw error;
  }
};

export const analyzeCompany = async (company: Company) => {
  try {
    const prompt = `Analise os dados: ${JSON.stringify(company)}. Forneça insights sobre saúde financeira.`;
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    return "Erro na análise.";
  }
};

