                      <Loader2 size={40} className="text-indigo-600 animate-spin" />
                      <div>
                        <p className="font-bold text-slate-900">Vascunhando a Web...</p>
                        <p className="text-slate-400 text-xs mt-1">Consultando Reclame Aqui, Google News e Diários Oficiais</p>
                      </div>
                    </div>
                  ) : (
                    <div className="space-y-6">
                      <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm prose prose-slate max-w-none prose-sm whitespace-pre-line text-slate-700 font-medium leading-relaxed">
                        {publicDataReport.text}
                      </div>

                      {/* Grounding Sources */}
                      <div className="space-y-3">
                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                          <ClipboardCheck size={12} /> Fontes Indexadas
                        </p>
                        <div className="flex flex-wrap gap-2">
                          {publicDataReport.sources.map((s: any, i: number) => (
                            <a 
                              key={i} 
                              href={s.web?.uri || '#'} 
