                            </a>
                          ))}
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Informações Institucionais */}
              <div className="space-y-6">
                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <AlertCircle size={14} /> Ficha Cadastral
                </h4>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-5 bg-white border border-slate-100 rounded-2xl shadow-sm">
                    <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">CNAE Principal</p>
                    <p className="text-sm font-bold text-slate-800 leading-tight">{selectedCompany.cnaeDescription}</p>
                    <span className="text-[10px] font-mono text-slate-400 mt-1 block">{selectedCompany.cnae}</span>
                  </div>
                  <div className="p-5 bg-white border border-slate-100 rounded-2xl shadow-sm">
                    <p className="text-[10px] font-bold text-slate-400 uppercase mb-1">Endereço</p>
                    <p className="text-sm font-bold text-slate-800 leading-tight">
                      {selectedCompany.address.city} - {selectedCompany.address.state}
                    </p>
                    <span className="text-[10px] text-slate-400 mt-1 block">{selectedCompany.address.neighborhood}</span>
                  </div>
                </div>
              </div>

              {/* Quadro de Sócios */}
              <div className="space-y-4">
                <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <Building size={14} /> Sócios-Administradores
                </h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                  {selectedCompany.partners.map((p, i) => (
                    <div key={i} className="p-4 bg-white border border-slate-100 rounded-2xl flex items-center gap-3">
                      <div className="w-8 h-8 bg-slate-50 rounded-lg flex items-center justify-center text-slate-400">
                        <Building size={14} />
                      </div>
                      <div>
                        <p className="text-sm font-bold text-slate-800">{p.name}</p>
                        <p className="text-[10px] text-slate-400 font-medium uppercase">{p.role}</p>
                      </div>
                    </div>
                  ))}
