import React, { useState, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import CompanyCard from './components/CompanyCard';
import Dashboard from './components/Dashboard';
import FilterModal from './components/FilterModal';
import { Company, ViewType, FilterState } from './types';
import { MOCK_COMPANIES } from './mockData';
import { 
  Search, 
  SlidersHorizontal, 
  Sparkles, 
  X, 
  MapPin, 
  Building, 
  Globe, 
  ShieldCheck,
  SearchCode,
  Loader2,
  ExternalLink,
  ClipboardCheck,
  Star,
  AlertCircle,
  ArrowRight
} from 'lucide-react';
import { fetchPublicDataReport } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState<FilterState>({
    sector: 'Todos',
    state: 'Todas',
    size: 'Todas'
  });

  const [selectedCompany, setSelectedCompany] = useState<Company | null>(null);
  const [publicDataReport, setPublicDataReport] = useState<{text: string, sources: any[]} | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  const filteredCompanies = useMemo(() => {
    return MOCK_COMPANIES.filter(c => {
      const cleanSearch = searchTerm.replace(/[^\d\w]/g, '').toLowerCase();
      const cleanCnpj = c.cnpj.replace(/[^\d]/g, '');

      const matchSearch = 
        c.tradeName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        c.legalName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        cleanCnpj.includes(cleanSearch) ||
        c.cnpj.includes(searchTerm);

      const matchState = filters.state === 'Todas' || c.address.state === filters.state;
      const matchSector = filters.sector === 'Todos' || c.cnaeDescription.toLowerCase().includes(filters.sector.toLowerCase());
      const matchSize = filters.size === 'Todas' || (
        filters.size === 'Pequena' ? c.capital <= 1000000 :
        filters.size === 'Média' ? (c.capital > 1000000 && c.capital <= 5000000) :
        c.capital > 5000000
      );
      return matchSearch && matchState && matchSize && matchSector;
    });
  }, [searchTerm, filters]);

  // Função para consulta direta (Manual Search)
  const handleDirectConsult = async () => {
    if (!searchTerm || searchTerm.length < 3) return;

    // Tenta encontrar nos locais primeiro
    const localMatch = filteredCompanies[0];

    if (localMatch && (localMatch.cnpj.includes(searchTerm) || localMatch.tradeName.toLowerCase().includes(searchTerm.toLowerCase()))) {
      setSelectedCompany(localMatch);
      setPublicDataReport(null);
    } else {
      // Se não encontrar, cria uma "Entidade Virtual" para consulta externa
      const isCnpj = /^\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}$/.test(searchTerm) || /^\d{14}$/.test(searchTerm);

      const virtualCompany: Company = {
        id: 'external',
        cnpj: isCnpj ? searchTerm : 'Consulta por Nome',
        legalName: !isCnpj ? searchTerm.toUpperCase() : 'Empresa Externa',
        tradeName: !isCnpj ? searchTerm : 'Resultado de Busca',
        status: 'Ativa',
        openingDate: new Date().toISOString(),
        capital: 0,
        cnae: '0000-0/00',
        cnaeDescription: 'Consulta Externa em Tempo Real',
        nature: 'Entidade Externa',
        address: { street: '', number: '', neighborhood: '', city: 'Brasil', state: 'BR', zipCode: '' },
        partners: [],
        contact: { email: '', phone: '' },
        financialHistory: [],
        competitors: [],
        recentNews: [],
        metrics: { employees: 0, growth: 0, marketShare: 0 }
      };

      setSelectedCompany(virtualCompany);
      setPublicDataReport(null);
      // Opcional: Já dispara a busca se for CNPJ
      if (isCnpj) {
        setIsSearching(true);
        try {
          const result = await fetchPublicDataReport(searchTerm, "Empresa");
          setPublicDataReport(result);
        } catch (e) {
          console.error(e);
        } finally {
          setIsSearching(false);
        }
      }
    }
  };

  const handlePublicDataSearch = async () => {
    if (!selectedCompany) return;
    setIsSearching(true);
    setPublicDataReport(null);
    try {
      const result = await fetchPublicDataReport(selectedCompany.cnpj, selectedCompany.tradeName || selectedCompany.legalName);
      setPublicDataReport(result);
    } catch (error) {
      alert("Erro na consulta de dados públicos.");
    } finally {
      setIsSearching(false);
    }
  };

  const extractRating = (text: string) => {
    const match = text.match(/AVALIAÇÃO FINAL:?\s*(\d+\.?\d*)/i);
    return match ? match[1] : null;
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex text-slate-900 font-['Inter']">
      <Sidebar 
        currentView={currentView} 
        setView={setView} 
        isOpen={isSidebarOpen} 
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        filters={filters}
        setFilters={setFilters}
      />

      <FilterModal 
        isOpen={isFilterModalOpen}
        onClose={() => setIsFilterModalOpen(false)}
        filters={filters}
        setFilters={setFilters}
      />

      <main className="flex-1 lg:ml-64 p-6 lg:p-12 transition-all">
        <header className="mb-10 max-w-6xl mx-auto">
          <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
            <div>
              <h1 className="text-3xl font-bold tracking-tight text-slate-900">
                {currentView === 'dashboard' ? 'Overview' : 'Consultar Dados'}
              </h1>
              <p className="text-slate-500 mt-1">Busca unificada por CNPJ ou Nome com scraping de IA.</p>
            </div>

            <div className="flex items-center gap-2 w-full lg:w-auto">
              <div className="relative group flex-1">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500" size={18} />
                <input 
                  type="text" 
                  placeholder="CNPJ ou Nome da Empresa..."
                  className="w-full lg:w-[400px] pl-12 pr-4 py-3.5 bg-white border border-slate-200 rounded-2xl shadow-sm outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-400 transition-all text-sm font-medium"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleDirectConsult()}
                />
              </div>
              <button 
                onClick={handleDirectConsult}
                className="bg-slate-900 text-white px-6 py-3.5 rounded-2xl font-bold hover:bg-slate-800 transition-all shadow-lg shadow-slate-200 flex items-center gap-2"
              >
                <span>Consultar</span>
                <ArrowRight size={18} />
              </button>
              <button 
                onClick={() => setIsFilterModalOpen(true)}
                className="p-3.5 bg-white border border-slate-200 rounded-2xl text-slate-600 hover:bg-slate-50 transition-all shadow-sm"
                title="Parâmetros de Filtro"
              >
                <SlidersHorizontal size={18} />
              </button>
            </div>
          </div>
        </header>

        <div className="max-w-6xl mx-auto">
          {currentView === 'dashboard' && <Dashboard companies={MOCK_COMPANIES} />}

          {(currentView === 'search' || currentView === 'dashboard') && (
            <section className="mt-8">
              <div className="flex items-center justify-between mb-6">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                  <ShieldCheck size={16} /> {searchTerm ? 'Resultados da Pesquisa' : 'Entidades Recomendadas'}
                </h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                {filteredCompanies.map(company => (
                  <CompanyCard 
                    key={company.id} 
                    company={company} 
                    onClick={(c) => {
                      setSelectedCompany(c);
                      setPublicDataReport(null);
                    }} 
                  />
                ))}
              </div>

              {filteredCompanies.length === 0 && searchTerm && (
                <div className="bg-white border-2 border-dashed border-slate-200 rounded-[2rem] p-12 text-center">
                  <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4">
                    <SearchCode size={28} className="text-slate-300" />
                  </div>
                  <h4 className="text-lg font-bold text-slate-900 mb-2">Empresa não encontrada no banco local</h4>
                  <p className="text-slate-500 mb-6">Deseja realizar uma consulta profunda via IA para "{searchTerm}"?</p>
                  <button 
                    onClick={handleDirectConsult}
                    className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all inline-flex items-center gap-2"
                  >
                    <Sparkles size={18} />
                    Consultar via Deep Search
                  </button>
                </div>
              )}
            </section>
          )}
        </div>
      </main>

      {/* PAINEL DE DADOS PÚBLICOS & SCRAPING */}
      {selectedCompany && (
        <div className="fixed inset-0 z-[110] flex justify-end">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => setSelectedCompany(null)} />
          <div className="relative w-full max-w-3xl bg-white h-full shadow-2xl flex flex-col overflow-hidden animate-in slide-in-from-right duration-300">
            {/* Header Detail */}
            <div className="p-6 border-b border-slate-100 flex items-center justify-between bg-white z-10">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-900 text-white rounded-xl flex items-center justify-center font-bold text-xl">
                  {selectedCompany.tradeName?.[0] || selectedCompany.legalName[0]}
                </div>
                <div>
                  <h2 className="text-xl font-bold text-slate-900">{selectedCompany.tradeName || selectedCompany.legalName}</h2>
                  <p className="text-slate-400 text-xs font-mono">{selectedCompany.cnpj}</p>
                </div>
              </div>
              <button onClick={() => setSelectedCompany(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400">
                <X size={20} />
              </button>
            </div>

            {/* Scroll Content */}
            <div className="flex-1 overflow-y-auto p-8 space-y-10 scrollbar-hide bg-white">

              {/* Seção de Dados Públicos & IA */}
              <div className="rounded-3xl border border-slate-100 overflow-hidden bg-slate-50/50">
                <div className="p-6 bg-white border-b border-slate-100 flex items-center justify-between">
                  <h4 className="font-bold text-slate-900 flex items-center gap-2">
                    <Globe size={18} className="text-indigo-600" />
                    Dados Públicos & Reputação
                  </h4>
                  {publicDataReport && (
                    <div className="flex items-center gap-2 px-3 py-1 bg-indigo-50 text-indigo-700 rounded-lg text-xs font-bold">
                      <Star size={14} fill="currentColor" />
                      Rating: {extractRating(publicDataReport.text) || 'N/A'}/10
                    </div>
                  )}
                </div>

                <div className="p-8">
                  {!publicDataReport && !isSearching ? (
                    <div className="text-center py-10">
                      <div className="w-16 h-16 bg-white rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-sm text-slate-400">
                        <SearchCode size={32} />
                      </div>
                      <h5 className="font-bold text-slate-900 mb-2">Consulta Avançada Reclame Aqui & Google</h5>
                      <p className="text-slate-500 text-sm mb-8 max-w-sm mx-auto">
                        Vascule tudo o que está indexado sobre esta empresa: reclamações, notícias e dados públicos.
                      </p>
                      <button 
                        onClick={handlePublicDataSearch}
                        className="bg-slate-900 text-white px-8 py-3.5 rounded-2xl font-bold shadow-lg hover:bg-slate-800 transition-all flex items-center gap-2 mx-auto"
                      >
                        <Sparkles size={18} />
                        Vascular Dados Públicos
                      </button>
                    </div>
