/**
 * Consulta Profunda de Dados Reais
 * Busca informações oficiais indexadas em sites de consulta de CNPJ e portais públicos.
 */
export const fetchPublicDataReport = async (cnpj: string, query: string) => {
  try {
    const prompt = `Aja como um analista de dados cadastrais. Localize informações REAIS e ATUAIS sobre a empresa: ${query} (CNPJ: ${cnpj}).

    INFORMAÇÕES OBRIGATÓRIAS PARA EXTRAIR (Se disponível publicamente):
    1. Nome Empresarial e Nome Fantasia corretos.
    2. Situação Cadastral (Ativa, Baixada, etc).
    3. Capital Social exato.
    4. Endereço Completo (Rua, Número, CEP, Cidade, UF).
    5. Quadro de Sócios e Administradores (QSA).
    6. CNAE Principal e Secundários.
    7. Reputação real no Reclame Aqui (Nota e Volume de Queixas).
    8. Notícias recentes de fontes de negócios (Exame, Valor, G1).

    REGRAS:
    - Se houver divergência entre fontes, priorize a informação mais recente.
    - Cite as URLs de onde os dados foram extraídos.
    - Se o CNPJ for inválido, informe imediatamente.

    ESTRUTURA DO RELATÓRIO:
    # DOSSIÊ CORPORATIVO REAL
    - [AVALIAÇÃO DE RISCO 0-10]
    - [DADOS CADASTRAIS]
    - [QUADRO SOCIETÁRIO]
    - [REPUTAÇÃO DIGITAL E RECLAME AQUI]
    - [INSIGHTS DE MERCADO]`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um sistema de busca de dados reais. Sua função é converter informações dispersas na web em um relatório estruturado e verídico. Não invente dados."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Real Data Fetch Error:", error);
    throw error;
  }
};

