        c.cnpj.replace(/\D/g, '').includes(searchTerm.replace(/\D/g, ''));
      return matchSearch;
    });
  }, [searchTerm]);

  const handleRealDataConsult = async (targetCnpj?: string, targetName?: string) => {
    const query = targetCnpj || targetName || searchTerm;
    if (!query || query.length < 3) return;

    const virtualCompany: Company = {
