import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Auditoria Real e Processos Judiciais (Empresas e Pessoas)
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = type === 'EMPRESA' 
      ? `REALIZE UMA AUDITORIA DE COMPLIANCE REAL PARA A EMPRESA: ${query} (CNPJ: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Portal da Transparência, Reclame Aqui, Casa dos Dados.
         Extraia processos, sócios, capital e reputação. PROIBIDO DADOS FICTÍCIOS.`
      : `REALIZE UMA PESQUISA DE ANTECEDENTES E DADOS PÚBLICOS PARA A PESSOA: ${query} (CPF: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Diários Oficiais, Portais de Transparência, LinkedIn (se disponível).
         Extraia processos judiciais, participações em empresas (QSA) e possíveis restrições públicas.
         REGRAS: Use apenas dados reais. Se não encontrar processos, diga "Sem ocorrências localizadas".`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um auditor sênior. Sua missão é extrair apenas dados verídicos. Não use placeholders ou dados de exemplo."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura de Licitações Públicas em tempo real
 */
export const scanPublicBiddings = async (keyword: string) => {
  try {
    const prompt = `VARREDURA DE LICITAÇÕES PÚBLICAS REAIS. Termo de busca: ${keyword}.
    Procure em: Portal Nacional de Contratações Públicas (PNCP), ComprasNet, Licitacoes-e (BB), Diários Oficiais da União (DOU) e Estados.

    PARA CADA LICITAÇÃO ENCONTRADA, EXTRAIA:
    1. Nome do Órgão Público.
    2. Modalidade (ex: Pregão Eletrônico, Tomada de Preços).
    3. Objeto/Descrição resumida.
    4. Data de Abertura ou Prazo.
    5. Link direto ou fonte.

    FORMATE COMO UM RELATÓRIO ESTRUTURADO DE OPORTUNIDADES. APENAS DADOS REAIS E ATUAIS.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um especialista em licitações e contratos públicos. Sua função é varrer a web em busca de editais abertos e oportunidades reais."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Bidding Scan Error:", error);
    throw error;
  }
};

