      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    throw error;
  }
};

/**
 * Varredura Avançada de Empresas (Leads) por UF, CNAE e CEP
 */
export const scanCompaniesByFilters = async (uf: string, cnae: string, cep: string) => {
  try {
    const prompt = `REALIZE UMA VARREDURA DE EMPRESAS REAIS COM OS SEGUINTES FILTROS:
    - ESTADO (UF): ${uf}
    - CNAE / ATIVIDADE: ${cnae}
    - PROXIMIDADE DO CEP: ${cep}

    FONTES: Casa dos Dados, CNPJ.biz, Econodata, QSA.ninja, Google Maps.

    REQUISITOS:
    1. Liste pelo menos 5 a 10 empresas reais que correspondam a esses critérios.
    2. Para cada empresa, informe: Nome Fantasia, CNPJ, Endereço e Atividade Principal.
    3. Forneça o link para a fonte do dado (ex: link da página na Casa dos Dados).
    4. PROIBIDO INVENTAR EMPRESAS. Se não houver resultados precisos, relate as mais próximas no estado.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um especialista em prospecção de dados B2B. Sua função é encontrar empresas reais através de fontes públicas indexadas."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Lead Scan Error:", error);
