import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Auditoria Real e Processos Judiciais
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = type === 'EMPRESA' 
      ? `REALIZE UMA AUDITORIA DE COMPLIANCE REAL PARA A EMPRESA: ${query} (CNPJ: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Portal da Transparência, Reclame Aqui, Casa dos Dados.
         Extraia processos, sócios, capital e reputação. PROIBIDO DADOS FICTÍCIOS.`
      : `REALIZE UMA PESQUISA DE ANTECEDENTES E DADOS PÚBLICOS PARA A PESSOA: ${query} (CPF: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Diários Oficiais, Portais de Transparência.
         Extraia processos judiciais e participações em empresas (QSA). APENAS DADOS REAIS.`

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um auditor sênior de dados reais brasileiros."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura de Licitações Públicas
 */
export const scanPublicBiddings = async (keyword: string) => {
  try {
    const prompt = `VARREDURA DE LICITAÇÕES PÚBLICAS REAIS. Termo: ${keyword}.
    Procure em: PNCP, ComprasNet, BB, Diários Oficiais. Extraia Órgão, Modalidade, Objeto, Data e Link.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    throw error;
  }
};

/**
 * Varredura Avançada de Empresas (Leads) por UF, Cidade, CNAE, CEP e Limite
 */
export const scanCompaniesByFilters = async (uf: string, city: string, cnae: string, cep: string, limit: number) => {
  try {
    const prompt = `REALIZE UMA VARREDURA DE EMPRESAS REAIS COM OS SEGUINTES FILTROS:
    - ESTADO (UF): ${uf}
    - CIDADE: ${city}
    - CNAE / ATIVIDADE: ${cnae}
    - PROXIMIDADE DO CEP: ${cep}
    - QUANTIDADE DESEJADA: ${limit}

    FONTES: Casa dos Dados, CNPJ.biz, Econodata, Google Maps (Google Meu Negócio).

    REQUISITOS OBRIGATÓRIOS PARA CADA LEAD:
    1. Nome Fantasia / Razão Social.
    2. CNPJ Válido.
    3. Endereço Completo.
    4. LISTA DE SÓCIOS (Extraia do QSA ou Casa dos Dados).
    5. LINK DO GOOGLE MEU NEGÓCIO (Se a empresa tiver perfil no Google Maps).
    6. Atividade Principal.

    IMPORTANTE: Retorne os dados em uma lista clara e estruturada. Se encontrar o link do Google Maps/Meu Negócio, inclua-o obrigatoriamente.
    Não invente dados.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um especialista em extração de leads B2B. Sua missão é fornecer uma lista de empresas reais com seus respectivos sócios e links de localização."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Lead Scan Error:", error);
    throw error;
  }
};

