  Search, 
  X, 
  MapPin, 
  Globe, 
  ShieldCheck,
  Loader2,
  ExternalLink,
  ArrowRight,
  DatabaseZap,
  Gavel,
  User,
  Fingerprint,
  Stamp,
  Target,
  Briefcase,
  Map,
  Download,
  Users,
  MapPinned,
  ChevronRight,
  Building2,
  Hash,
  Star,
  CheckCircle2,
  Navigation
} from 'lucide-react';
import { fetchPublicDataReport, scanPublicBiddings, scanCompaniesStream } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [searchMode, setSearchMode] = useState<SearchMode>('CNPJ');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [leadParams, setLeadParams] = useState<LeadScanParams>({ uf: '', city: '', cnae: '', cep: '', limit: 10 });

  const [filters, setFilters] = useState<FilterState>({
    sector: 'Todos',
    state: 'Todas',
    size: 'Todas'
  });

  const [selectedItem, setSelectedItem] = useState<{name: string, identifier: string, type: 'EMPRESA' | 'PESSOA'} | null>(null);
  const [biddingResults, setBiddingResults] = useState<{text: string, sources: any[]} | null>(null);
  const [publicDataReport, setPublicDataReport] = useState<{text: string, sources: any[]} | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  // Estados para Varredura de Leads com Streaming
  const [streamingText, setStreamingText] = useState('');
  const [leads, setLeads] = useState<Lead[]>([]);

  // Parser simples para extrair leads do texto em streaming
  useEffect(() => {
    const leadBlocks = streamingText.split('---LEAD_START---').slice(1);
    const parsedLeads: Lead[] = leadBlocks.map(block => {
      const lines = block.split('\n').map(l => l.trim()).filter(l => l !== '');
      const findValue = (key: string) => lines.find(l => l.startsWith(key))?.split(':')?.[1]?.trim() || '';

      const sociosText = findValue('SOCIOS');
      const partners = sociosText ? sociosText.split(',').map(s => s.trim()) : [];
      const gmn = findValue('GMN');

      return {
        name: findValue('EMPRESA'),
        cnpj: findValue('CNPJ'),
        address: findValue('CIDADE'),
        partners: partners,
        googleBusinessLink: gmn.startsWith('http') ? gmn : undefined,
        activity: findValue('ATIVIDADE')
      };
    }).filter(l => l.name); // Garante que só mostramos o que tem nome

    setLeads(parsedLeads);
  }, [streamingText]);

  const handleRealDataConsult = async (targetIdentifier?: string, targetName?: string) => {
    const query = targetIdentifier || targetName || searchTerm;
    if (!query || query.length < 3) return;
    const identifier = targetIdentifier || (searchMode !== 'NOME' ? query : 'Busca por Nome');
    const name = targetName || (searchMode === 'NOME' ? query : 'Consulta Verificada');
    const type = searchMode === 'CPF' ? 'PESSOA' : 'EMPRESA';
    setSelectedItem({ name, identifier, type });
    setPublicDataReport(null);
    setIsSearching(true);
    try {
      const result = await fetchPublicDataReport(identifier, query, type);
      setPublicDataReport(result);
    } catch (error) {
      alert("Erro ao conectar com as fontes de dados reais.");
    } finally { setIsSearching(false); }
  };

  const handleBiddingScan = async () => {
    if (!searchTerm || searchTerm.length < 3) return;
    setIsSearching(true);
    setBiddingResults(null);
    try {
      const result = await scanPublicBiddings(searchTerm);
      setBiddingResults(result);
    } catch (error) { alert("Erro na varredura de licitações."); }
    finally { setIsSearching(false); }
  };

  const handleLeadScan = async () => {
    if (!leadParams.uf && !leadParams.city && !leadParams.cnae) {
      alert("Por favor, preencha pelo menos o Estado, Cidade ou CNAE.");
      return;
    }

    setIsSearching(true);
    setStreamingText('');
    setLeads([]);

    try {
      const stream = await scanCompaniesStream(
        leadParams.uf, 
        leadParams.city, 
        leadParams.cnae, 
        leadParams.cep, 
        leadParams.limit
      );

      for await (const chunk of stream) {
        setStreamingText(prev => prev + chunk.text);
      }
    } catch (error) { 
      alert("Erro na varredura de leads."); 
    } finally { 
      setIsSearching(false); 
    }
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex text-slate-900 font-['Inter']">
      <Sidebar 
        currentView={currentView} 
        setView={setView} 
        isOpen={isSidebarOpen} 
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        filters={filters}
        setFilters={setFilters}
      />

      <main className="flex-1 lg:ml-64 p-6 lg:p-12 transition-all">
        {/* VIEW: VARREDURA DE LEADS (STREAMING) */}
        {currentView === 'lead_scan' && (
          <div className="max-w-7xl mx-auto space-y-10">
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-8 h-8 bg-indigo-100 rounded-lg flex items-center justify-center text-indigo-600">
                    <Target size={18} />
                  </div>
                  <span className="text-xs font-black text-indigo-600 uppercase tracking-[0.2em]">Live Lead Scanner</span>
                </div>
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">Prospecção de Leads em Tempo Real</h1>
                <p className="text-slate-500 mt-2 font-medium">Os leads aparecerão abaixo assim que forem localizados na rede.</p>
              </div>

              <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
                <div className="px-4 py-2 text-center">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Encontrados</p>
                  <p className="text-xl font-bold text-indigo-600">{leads.length}</p>
                </div>
                <div className="w-px bg-slate-100 my-2 mx-2"></div>
                <div className="px-4 py-2 text-center">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Status</p>
                  <div className="flex items-center gap-2 mt-1">
                    {isSearching ? <Loader2 size={14} className="animate-spin text-amber-500" /> : <CheckCircle2 size={14} className="text-emerald-500" />}
                    <span className="text-xs font-bold text-slate-700">{isSearching ? 'Varrendo...' : 'Pronto'}</span>
                  </div>
                </div>
              </div>
            </header>

            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 mb-8">
                <div className="space-y-2 lg:col-span-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 flex items-center gap-1">UF</label>
                  <input type="text" placeholder="Ex: SP" className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-400 transition-all font-bold text-sm" value={leadParams.uf} onChange={e => setLeadParams({...leadParams, uf: e.target.value})} />
                </div>
                <div className="space-y-2 lg:col-span-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 flex items-center gap-1">Cidade</label>
                  <input type="text" placeholder="Ex: Curitiba" className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-400 transition-all font-bold text-sm" value={leadParams.city} onChange={e => setLeadParams({...leadParams, city: e.target.value})} />
                </div>
                <div className="space-y-2 lg:col-span-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-2 flex items-center gap-1">CNAE / Nicho</label>
                  <input type="text" placeholder="Ex: Contabilidade" className="w-full bg-slate-50 border border-slate-200 rounded-2xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-400 transition-all font-bold text-sm" value={leadParams.cnae} onChange={e => setLeadParams({...leadParams, cnae: e.target.value})} />
                </div>
