               publicDataReport ? <div className="space-y-10"><div className="bg-white p-10 rounded-[2.5rem] border border-slate-100 shadow-sm"><div className="prose prose-slate max-w-none text-slate-700 text-sm whitespace-pre-line">{publicDataReport.text}</div></div></div> : null}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

