import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Auditoria Real e Processos Judiciais
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = type === 'EMPRESA' 
      ? `REALIZE UMA AUDITORIA DE COMPLIANCE REAL PARA A EMPRESA: ${query} (CNPJ: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Portal da Transparência, Reclame Aqui, Casa dos Dados.
         Extraia processos, sócios, capital e reputação. PROIBIDO DADOS FICTÍCIOS.`
      : `REALIZE UMA PESQUISA DE ANTECEDENTES E DADOS PÚBLICOS PARA A PESSOA: ${query} (CPF: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Diários Oficiais, Portais de Transparência.
         Extraia processos judiciais e participações em empresas (QSA). APENAS DADOS REAIS.`

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um auditor sênior de dados reais brasileiros."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura de Licitações Públicas
 */
export const scanPublicBiddings = async (keyword: string) => {
  try {
    const prompt = `VARREDURA DE LICITAÇÕES PÚBLICAS REAIS. Termo: ${keyword}.
    Procure em: PNCP, ComprasNet, BB, Diários Oficiais. Extraia Órgão, Modalidade, Objeto, Data e Link.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    throw error;
  }
};

/**
 * Varredura Avançada de Empresas (Leads) com STREAMING para alta performance
 * Foco total em Casa dos Dados e extração de Sócios/Telefones
 */
export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number) => {
  try {
    const prompt = `VARREDURA DE PROSPECÇÃO B2B - LIMITE: ${limit} LEADS REAIS.
    FILTROS: UF: ${uf}, CIDADE: ${city}, CNAE: ${cnae}, CEP: ${cep}.

    FONTES OBRIGATÓRIAS: Casa dos Dados, CNPJ.biz, Econodata e Google Maps.

    PARA CADA EMPRESA ENCONTRADA, EXTRAIA DADOS REAIS E FORMATE ASSIM:
    ---LEAD_START---
    EMPRESA: [Nome Fantasia ou Razão Social]
    CNPJ: [CNPJ formatado]
    CIDADE: [Cidade/UF]
    SOCIOS: [Nome dos Sócios separados por vírgula - BUSCAR NA CASA DOS DADOS]
    TELEFONES: [Telefones de contato encontrados]
    GMN: [Link Google Maps / Google Meu Negócio]
    ATIVIDADE: [Descrição da Atividade Econômica]
    ---LEAD_END---

    REGRAS CRÍTICAS:
    1. PRIORIZE DADOS DA CASA DOS DADOS PARA SÓCIOS E TELEFONES.
    2. Liste apenas empresas REAIS.
    3. Comece a gerar os blocos imediatamente.
    4. Não adicione texto fora dos blocos ---LEAD_START--- e ---LEAD_END---.`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um especialista em extração de dados públicos de empresas (Casa dos Dados). Forneça apenas dados reais e estruturados conforme solicitado."
      }
    });

    return responseStream;
  } catch (error) {
    console.error("Lead Stream Error:", error);
    throw error;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import CompanyCard from './components/CompanyCard';
import Dashboard from './components/Dashboard';
import FilterModal from './components/FilterModal';
import { Company, ViewType, FilterState, SearchMode, LeadScanParams, Lead } from './types';
import { MOCK_COMPANIES } from './mockData';
import { 
  Search, 
  X, 
  MapPin, 
  Globe, 
  ShieldCheck,
  Loader2,
  ExternalLink,
  ArrowRight,
  DatabaseZap,
  Gavel,
  User,
  Fingerprint,
  Stamp,
  Target,
  Briefcase,
  Map,
  Download,
  Users,
  MapPinned,
  ChevronRight,
  Building2,
  Hash,
  Star,
  CheckCircle2,
  Navigation,
  Phone,
  Info
} from 'lucide-react';
import { fetchPublicDataReport, scanPublicBiddings, scanCompaniesStream } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [searchMode, setSearchMode] = useState<SearchMode>('CNPJ');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [leadParams, setLeadParams] = useState<LeadScanParams>({ uf: '', city: '', cnae: '', cep: '', limit: 10 });

  const [filters, setFilters] = useState<FilterState>({
    sector: 'Todos',
    state: 'Todas',
    size: 'Todas'
  });

  const [selectedItem, setSelectedItem] = useState<{name: string, identifier: string, type: 'EMPRESA' | 'PESSOA'} | null>(null);
  const [biddingResults, setBiddingResults] = useState<{text: string, sources: any[]} | null>(null);
  const [publicDataReport, setPublicDataReport] = useState<{text: string, sources: any[]} | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  // Estados para Varredura de Leads com Streaming
  const [streamingText, setStreamingText] = useState('');
  const [leads, setLeads] = useState<Lead[]>([]);

  // Parser para extrair leads do texto em streaming
  useEffect(() => {
    const leadBlocks = streamingText.split('---LEAD_START---').slice(1);
    const parsedLeads: Lead[] = leadBlocks.map(block => {
      const cleanBlock = block.split('---LEAD_END---')[0];
      const lines = cleanBlock.split('\n').map(l => l.trim()).filter(l => l !== '');

      const findValue = (key: string) => {
        const line = lines.find(l => l.toUpperCase().startsWith(key.toUpperCase()));
        return line ? line.substring(line.indexOf(':') + 1).trim() : '';
      };

      const sociosText = findValue('SOCIOS');
      const partners = sociosText ? sociosText.split(',').map(s => s.trim()).filter(s => s) : [];

      const telefonesText = findValue('TELEFONES');
      const phones = telefonesText ? telefonesText.split(',').map(p => p.trim()).filter(p => p) : [];

      const gmn = findValue('GMN');

      return {
        name: findValue('EMPRESA'),
        cnpj: findValue('CNPJ'),
        address: findValue('CIDADE'),
        partners: partners,
        phones: phones,
        googleBusinessLink: gmn.startsWith('http') ? gmn : undefined,
        activity: findValue('ATIVIDADE')
      };
    }).filter(l => l.name);

    setLeads(parsedLeads);
  }, [streamingText]);

  const handleRealDataConsult = async (targetIdentifier?: string, targetName?: string) => {
    const query = targetIdentifier || targetName || searchTerm;
    if (!query || query.length < 3) return;
    const identifier = targetIdentifier || (searchMode !== 'NOME' ? query : 'Busca por Nome');
    const name = targetName || (searchMode === 'NOME' ? query : 'Consulta Verificada');
    const type = searchMode === 'CPF' ? 'PESSOA' : 'EMPRESA';
    setSelectedItem({ name, identifier, type });
    setPublicDataReport(null);
    setIsSearching(true);
    try {
      const result = await fetchPublicDataReport(identifier, query, type);
      setPublicDataReport(result);
    } catch (error) {
      alert("Erro ao conectar com as fontes de dados reais.");
    } finally { setIsSearching(false); }
  };

  const handleBiddingScan = async () => {
    if (!searchTerm || searchTerm.length < 3) return;
    setIsSearching(true);
    setBiddingResults(null);
    try {
      const result = await scanPublicBiddings(searchTerm);
      setBiddingResults(result);
    } catch (error) { alert("Erro na varredura de licitações."); }
    finally { setIsSearching(false); }
  };

  const handleLeadScan = async () => {
    if (!leadParams.uf && !leadParams.city && !leadParams.cnae) {
      alert("Por favor, preencha pelo menos o Estado, Cidade ou CNAE.");
      return;
    }

    setIsSearching(true);
    setStreamingText('');
    setLeads([]);

    try {
      const stream = await scanCompaniesStream(
        leadParams.uf, 
        leadParams.city, 
        leadParams.cnae, 
        leadParams.cep, 
        leadParams.limit
      );

      for await (const chunk of stream) {
        setStreamingText(prev => prev + chunk.text);
      }
    } catch (error) { 
      alert("Erro na varredura de leads."); 
    } finally { 
      setIsSearching(false); 
    }
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex text-slate-900 font-['Inter']">
      <Sidebar 
        currentView={currentView} 
        setView={setView} 
        isOpen={isSidebarOpen} 
        toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        filters={filters}
        setFilters={setFilters}
      />

      <main className="flex-1 lg:ml-64 p-6 lg:p-12 transition-all">
        {currentView === 'lead_scan' && (
          <div className="max-w-7xl mx-auto space-y-10">
            <header className="flex flex-col md:flex-row md:items-end justify-between gap-6">
              <div>
                <div className="flex items-center gap-2 mb-2">
                  <div className="w-8 h-8 bg-indigo-100 rounded-lg flex items-center justify-center text-indigo-600">
                    <Target size={18} />
                  </div>
                  <span className="text-xs font-black text-indigo-600 uppercase tracking-[0.2em]">Scanner de Leads Casa dos Dados</span>
                </div>
                <h1 className="text-4xl font-black text-slate-900 tracking-tight">Prospecção B2B com Sócios</h1>
                <p className="text-slate-500 mt-2 font-medium">Dados extraídos de bases oficiais com foco em QSA e telefones.</p>
              </div>

              <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-slate-100">
                <div className="px-4 py-2 text-center">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Leads Captados</p>
                  <p className="text-xl font-bold text-indigo-600">{leads.length}</p>
                </div>
                <div className="w-px bg-slate-100 my-2 mx-2"></div>
                <div className="px-4 py-2 text-center">
                  <p className="text-[10px] font-black text-slate-400 uppercase">Motor de Busca</p>
                  <div className="flex items-center gap-2 mt-1">
                    {isSearching ? <Loader2 size={14} className="animate-spin text-amber-500" /> : <CheckCircle2 size={14} className="text-emerald-500" />}
                    <span className="text-xs font-bold text-slate-700">{isSearching ? 'Buscando...' : 'Ativo'}</span>
                  </div>
                </div>
              </div>
            </header>

