import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Auditoria Real e Processos Judiciais
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = type === 'EMPRESA' 
      ? `REALIZE UMA AUDITORIA DE COMPLIANCE REAL PARA A EMPRESA: ${query} (CNPJ: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Portal da Transparência, Reclame Aqui, Casa dos Dados.
         Extraia processos, sócios, capital e reputação. PROIBIDO DADOS FICTÍCIOS.`
      : `REALIZE UMA PESQUISA DE ANTECEDENTES E DADOS PÚBLICOS PARA A PESSOA: ${query} (CPF: ${identifier}).
         Pesquise em: Jusbrasil, Escavador, Diários Oficiais, Portais de Transparência.
         Extraia processos judiciais e participações em empresas (QSA). APENAS DADOS REAIS.`

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um auditor sênior de dados reais brasileiros."
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura de Licitações Públicas
 */
export const scanPublicBiddings = async (keyword: string) => {
  try {
    const prompt = `VARREDURA DE LICITAÇÕES PÚBLICAS REAIS. Termo: ${keyword}.
    Procure em: PNCP, ComprasNet, BB, Diários Oficiais. Extraia Órgão, Modalidade, Objeto, Data e Link.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    throw error;
  }
};

/**
 * Varredura Avançada de Empresas (Leads) com STREAMING
 * FOCO TOTAL EM EXATIDÃO DE CNPJ E SÓCIOS DA CASA DOS DADOS
 */
export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number) => {
  try {
    const prompt = `VOCÊ DEVE ATUAR COMO UM EXTRATOR DE DADOS RIGOROSO.
    OBJETIVO: Encontrar ${limit} empresas REAIS em ${city}/${uf} do setor ${cnae}.

    PARA CADA LEAD, VOCÊ DEVE OBRIGATORIAMENTE:
    1. Usar a pesquisa do Google para localizar o link da empresa no site casadosdados.com.br.
    2. Extrair o CNPJ EXATO que consta na página.
    3. Listar todos os SÓCIOS (QSA) conforme aparecem na Casa dos Dados.
    4. Extrair os TELEFONES listados.

    FORMATO DE SAÍDA (MANTENHA RIGOROSAMENTE):
    ---LEAD_START---
    EMPRESA: [Nome Fantasia]
    CNPJ: [CNPJ Real verificado]
    CIDADE: [Cidade/UF]
    SOCIOS: [Nome dos Sócios separados por vírgula]
    TELEFONES: [Telefones REAIS encontrados]
    GMN: [Link Google Maps / Google Meu Negócio]
    FONTE: [Link da página na Casa dos Dados]
    ATIVIDADE: [Descrição do CNAE]
    ---LEAD_END---

    PROIBIDO:
    - Inventar CNPJs ou formatá-los de forma genérica.
    - Omitir sócios se eles estiverem na Casa dos Dados.
    - Se não encontrar a empresa na Casa dos Dados, não a liste.`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um minerador de dados especializado em bases de dados empresariais brasileiras. Sua prioridade absoluta é a precisão do CNPJ e do Quadro Societário (QSA) extraídos da Casa dos Dados."
      }
    });

    return responseStream;
  } catch (error) {
    console.error("Lead Stream Error:", error);
    throw error;
  }
};

