import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import CompanyCard from './components/CompanyCard';
import Dashboard from './components/Dashboard';
import FilterModal from './components/FilterModal';
import { Company, ViewType, FilterState, SearchMode, LeadScanParams, Lead } from './types';
import { MOCK_COMPANIES } from './mockData';
import { 
  Search, 
  X, 
  MapPin, 
  Globe, 
  ShieldCheck,
  Loader2,
  ExternalLink,
  ArrowRight,
  DatabaseZap,
  Gavel,
  User,
  Fingerprint,
  Stamp,
  Target,
  Briefcase,
  Map,
  Download,
  Users,
  MapPinned,
  ChevronRight,
  Building2,
  Hash,
  Star,
  CheckCircle2,
  Navigation,
  Phone,
  Info,
  Link2
} from 'lucide-react';
import { fetchPublicDataReport, scanPublicBiddings, scanCompaniesStream } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [searchMode, setSearchMode] = useState<SearchMode>('CNPJ');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [leadParams, setLeadParams] = useState<LeadScanParams>({ uf: '', city: '', cnae: '', cep: '', limit: 10 });

  const [filters, setFilters] = useState<FilterState>({
    sector: 'Todos',
    state: 'Todas',
    size: 'Todas'
  });

  const [selectedItem, setSelectedItem] = useState<{name: string, identifier: string, type: 'EMPRESA' | 'PESSOA'} | null>(null);
  const [biddingResults, setBiddingResults] = useState<{text: string, sources: any[]} | null>(null);
  const [publicDataReport, setPublicDataReport] = useState<{text: string, sources: any[]} | null>(null);
  const [isSearching, setIsSearching] = useState(false);

  // Estados para Varredura de Leads com Streaming
  const [streamingText, setStreamingText] = useState('');
  const [leads, setLeads] = useState<Lead[]>([]);

  // Parser aprimorado para extrair leads do texto em streaming
  useEffect(() => {
    const leadBlocks = streamingText.split('---LEAD_START---').slice(1);
    const parsedLeads: Lead[] = leadBlocks.map(block => {
      const cleanBlock = block.split('---LEAD_END---')[0];
      const lines = cleanBlock.split('\n').map(l => l.trim()).filter(l => l !== '');

      const findValue = (key: string) => {
        const line = lines.find(l => l.toUpperCase().startsWith(key.toUpperCase()));
        return line ? line.substring(line.indexOf(':') + 1).trim() : '';
      };

      const sociosText = findValue('SOCIOS');
      const partners = sociosText ? sociosText.split(',').map(s => s.trim()).filter(s => s) : [];

      const telefonesText = findValue('TELEFONES');
      const phones = telefonesText ? telefonesText.split(',').map(p => p.trim()).filter(p => p) : [];

      const gmn = findValue('GMN');
      const fonte = findValue('FONTE');

      return {
        name: findValue('EMPRESA'),
        cnpj: findValue('CNPJ'),
        address: findValue('CIDADE'),
        partners: partners,
        phones: phones,
        googleBusinessLink: gmn.startsWith('http') ? gmn : undefined,
        sourceLink: fonte.startsWith('http') ? fonte : undefined,
        activity: findValue('ATIVIDADE')
      };
    }).filter(l => l.name);

    setLeads(parsedLeads);
  }, [streamingText]);

  const handleRealDataConsult = async (targetIdentifier?: string, targetName?: string) => {
    const query = targetIdentifier || targetName || searchTerm;
    if (!query || query.length < 3) return;
    const identifier = targetIdentifier || (searchMode !== 'NOME' ? query : 'Busca por Nome');
    const name = targetName || (searchMode === 'NOME' ? query : 'Consulta Verificada');
    const type = searchMode === 'CPF' ? 'PESSOA' : 'EMPRESA';
    setSelectedItem({ name, identifier, type });
    setPublicDataReport(null);
    setIsSearching(true);
    try {
      const result = await fetchPublicDataReport(identifier, query, type);
      setPublicDataReport(result);
    } catch (error) {
      alert("Erro ao conectar com as fontes de dados reais.");
    } finally { setIsSearching(false); }
  };

  const handleBiddingScan = async () => {
    if (!searchTerm || searchTerm.length < 3) return;
    setIsSearching(true);
    setBiddingResults(null);
    try {
      const result = await scanPublicBiddings(searchTerm);
      setBiddingResults(result);
    } catch (error) { alert("Erro na varredura de licitações."); }
    finally { setIsSearching(false); }
  };

