import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Auditoria Real e Processos Judiciais
 * Agora usando Flash para velocidade instantânea
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = type === 'EMPRESA' 
      ? `AUDITORIA EXPRESSA: ${query} (${identifier}).
         Fontes: Casa dos Dados, Jusbrasil, Reclame Aqui.
         Extraia: Sócios, Processos, Telefones. DIRETO AO PONTO.`
      : `PESQUISA EXPRESSA: ${query} (${identifier}).
         Fontes: Escavador, Jusbrasil, Diários Oficiais.
         Extraia: Processos e Empresas. DIRETO AO PONTO.`

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um extrator de dados ultra-rápido. Ignore introduções. Forneça apenas fatos.",
        thinkingConfig: { thinkingBudget: 0 } // Desativa o tempo de raciocínio para resposta imediata
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura Avançada de Empresas (Leads) com Gemini 3 FLASH
 * Otimizado para latência mínima e extração direta da Casa dos Dados
 */
export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number) => {
  try {
    const prompt = `EXTRAÇÃO IMEDIATA - SITE: casadosdados.com.br
    BUSCAR: ${limit} empresas em ${city}/${uf}, setor ${cnae}, CEP inicial ${cep}.

    PARA CADA EMPRESA, EMITA O BLOCO ASSIM QUE LOCALIZAR:
    ---LEAD_START---
    EMPRESA: [Nome]
    CNPJ: [CNPJ EXATO DA CASA DOS DADOS]
    CIDADE: [Cidade/UF]
    SOCIOS: [Nomes dos Sócios da página oficial]
    TELEFONES: [Telefones da página oficial]
    FONTE: [Link direto CasadosDados]
    ATIVIDADE: [CNAE]
    ---LEAD_END---

    REGRAS DE VELOCIDADE:
    1. USE O MODELO FLASH PARA RESPOSTA INSTANTÂNEA.
    2. NÃO EXPLIQUE O QUE ESTÁ FAZENDO.
    3. FOQUE 100% NA PRECISÃO DO CNPJ E SÓCIOS.
    4. SE NÃO ACHAR NA CASA DOS DADOS, PULE PARA A PRÓXIMA.`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um robô de extração de dados da Casa dos Dados. Sua única missão é velocidade e precisão de CNPJ/Sócios. Latência é sua maior prioridade.",
        thinkingConfig: { thinkingBudget: 0 } // Resposta começa no milissegundo zero
      }
    });

    return responseStream;
  } catch (error) {
    console.error("Lead Stream Error:", error);
    throw error;
  }
};

