import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Consulta de Auditoria Real e Processos Judiciais - MODO DOSSIÊ COMPLETO
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = `REALIZE UMA INVESTIGAÇÃO DE CAMPO DIGITAL PARA: ${query} (${identifier}).

    FONTES OBRIGATÓRIAS:
    1. JURÍDICO: Jusbrasil, Escavador, Diários Oficiais (Processos ativos/passivos).
    2. CADASTRAL: Casa dos Dados, QSA Oficial, Portais de Transparência.
    3. SOCIAL: LinkedIn, Instagram, Facebook, Twitter/X (Contas vinculadas).
    4. REPUTAÇÃO: Reclame Aqui, Google Reviews, Notícias locais.

    ESTRUTURE O RELATÓRIO EXATAMENTE COM ESTAS MARCAÇÕES PARA O PARSER:

    #SECAO_RESUMO#
    [Resumo executivo de 3 linhas sobre a entidade]
    NÍVEL_DE_RISCO: [BAIXO | MÉDIO | ALTO]

    #SECAO_DADOS#
    [Dados principais: Fundação, Capital, Sócios, Endereço completo]

    #SECAO_JURIDICO#
    [Lista de processos encontrados ou 'Nenhum registro encontrado']

    #SECAO_SOCIAL#
    [Links e resumo da presença em redes sociais e pegada digital]

    #SECAO_NOTICIAS#
    [Citações recentes na mídia ou portais de notícias]

    REGRAS:
    - Seja extremamente factual.
    - Se encontrar processos, cite o tribunal.
    - Se encontrar redes sociais, descreva o volume de seguidores/atividade.
    - Se for empresa, detalhe os sócios encontrados na Casa dos Dados.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um analista de inteligência (OSINT). Seu objetivo é compilar um dossiê estruturado e visual a partir de dados reais da web brasileira.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

