export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number) => {
  try {
    const prompt = `BUSCA OSINT - CASA DOS DADOS: ${limit} leads em ${city}/${uf}, setor ${cnae}.
    Foco em extrair SÓCIOS e TELEFONES REAIS.`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um robô de extração de dados. Formate em blocos ---LEAD_START--- e ---LEAD_END---.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return responseStream;
  } catch (error) {
    console.error("Lead Stream Error:", error);
    throw error;
  }
};

