                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">Cap. Social Min.</label>
                    <input type="text" placeholder="Ex: 100.000" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.minCapital} onChange={e => setLeadParams({...leadParams, minCapital: e.target.value})} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">CEP Ref.</label>
                    <input type="text" placeholder="00000-000" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.cep} onChange={e => setLeadParams({...leadParams, cep: e.target.value})} />
                  </div>
