import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import CompanyCard from './components/CompanyCard';
import Dashboard from './components/Dashboard';
import FilterModal from './components/FilterModal';
import { Company, ViewType, FilterState, SearchMode, LeadScanParams, Lead } from './types';
import { MOCK_COMPANIES } from './mockData';
import { 
  Search, X, MapPin, Globe, ShieldCheck, Loader2, ArrowRight, DatabaseZap, Gavel, 
  User, Target, Briefcase, Users, Navigation, Phone, Info, Link2, Zap, 
  Scale, Share2, Newspaper, AlertTriangle, CheckCircle, FileText,
  Hash, Building2, Download, Coins, SearchCode, Store
} from 'lucide-react';
import { fetchPublicDataReport, scanPublicBiddings, scanCompaniesStream } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [searchMode, setSearchMode] = useState<SearchMode>('CNPJ');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [leadParams, setLeadParams] = useState<LeadScanParams>({ 
    uf: '', 
    city: '', 
    cnae: '', 
    cep: '', 
    limit: 10,
    minCapital: ''
  });

  const [selectedItem, setSelectedItem] = useState<{name: string, identifier: string, type: 'EMPRESA' | 'PESSOA'} | null>(null);
  const [publicDataReport, setPublicDataReport] = useState<{text: string, sources: any[]} | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [streamingText, setStreamingText] = useState('');
  const [leads, setLeads] = useState<Lead[]>([]);

  // Parser para Leads (Lead Scan) - Suporta Multi-Fonte, Capital e GMN
  useEffect(() => {
    const leadBlocks = streamingText.split('---LEAD_START---').slice(1);
    const parsedLeads: Lead[] = leadBlocks.map(block => {
      const cleanBlock = block.split('---LEAD_END---')[0];
      const lines = cleanBlock.split('\n').map(l => l.trim()).filter(l => l !== '');
      const findValue = (key: string) => {
        const line = lines.find(l => l.toUpperCase().startsWith(key.toUpperCase()));
        return line ? line.substring(line.indexOf(':') + 1).trim() : '';
      };
      return {
        sourceName: findValue('FONTE_NOME') || 'Web Search',
        name: findValue('EMPRESA'),
        cnpj: findValue('CNPJ'),
        address: findValue('CIDADE'),
        partners: findValue('SOCIOS').split(',').map(s => s.trim()).filter(s => s),
        phones: findValue('TELEFONES').split(',').map(p => p.trim()).filter(p => p),
        googleBusinessLink: findValue('GMN'),
        sourceLink: findValue('FONTE'),
        activity: findValue('ATIVIDADE'),
        capitalSocial: findValue('CAPITAL')
      };
    }).filter(l => l.name);
    setLeads(parsedLeads);
  }, [streamingText]);

  const handleRealDataConsult = async (targetIdentifier?: string, targetName?: string) => {
    const query = targetIdentifier || targetName || searchTerm;
    if (!query || query.length < 3) return;
    const identifier = targetIdentifier || (searchMode !== 'NOME' ? query : 'Busca por Nome');
    const name = targetName || (searchMode === 'NOME' ? query : 'Investigação');
    const type = searchMode === 'CPF' ? 'PESSOA' : 'EMPRESA';
    setSelectedItem({ name, identifier, type });
    setPublicDataReport(null);
    setIsSearching(true);
    try {
      const result = await fetchPublicDataReport(identifier, query, type);
      setPublicDataReport(result);
    } catch (error) {
      alert("Erro ao conectar com as fontes OSINT.");
    } finally { setIsSearching(false); }
  };

  const handleLeadScan = async () => {
    if (!leadParams.uf && !leadParams.city && !leadParams.cnae) {
      alert("Informe pelo menos UF, Cidade ou CNAE para começar.");
      return;
    }
    setIsSearching(true);
    setStreamingText('');
    setLeads([]);
    try {
      const stream = await scanCompaniesStream(
        leadParams.uf, 
        leadParams.city, 
        leadParams.cnae, 
        leadParams.cep, 
        leadParams.limit,
        leadParams.minCapital
      );
      for await (const chunk of stream) {
        setStreamingText(prev => prev + chunk.text);
      }
    } catch (error) { 
      alert("Erro na varredura multi-fonte."); 
    } finally { 
      setIsSearching(false); 
    }
  };

  const parseDossie = (text: string) => {
    const sections = {
      resumo: text.split('#SECAO_RESUMO#')[1]?.split('#SECAO_DADOS#')[0] || '',
      dados: text.split('#SECAO_DADOS#')[1]?.split('#SECAO_JURIDICO#')[0] || '',
      juridico: text.split('#SECAO_JURIDICO#')[1]?.split('#SECAO_SOCIAL#')[0] || '',
      social: text.split('#SECAO_SOCIAL#')[1]?.split('#SECAO_NOTICIAS#')[0] || '',
      noticias: text.split('#SECAO_NOTICIAS#')[1] || ''
    };
    const risk = sections.resumo.includes('RISCO: ALTO') ? 'alto' : sections.resumo.includes('RISCO: MÉDIO') ? 'medio' : 'baixo';
    return { sections, risk };
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex text-slate-900 font-['Inter']">
      <Sidebar currentView={currentView} setView={setView} isOpen={isSidebarOpen} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} filters={{} as any} setFilters={() => {}} />

      <main className="flex-1 lg:ml-64 p-6 lg:p-12">
        <header className="mb-10 max-w-6xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">DataCorp OSINT</h1>
            <p className="text-slate-500 font-medium">Investigação multi-fonte e Google Business.</p>
          </div>
          <div className="flex gap-3 bg-white p-2 rounded-2xl shadow-sm border border-slate-100">
            <input 
              type="text" 
              placeholder={`Consultar ${searchMode}...`}
              className="pl-4 pr-4 py-2 bg-slate-50 border-none outline-none rounded-xl text-sm font-bold w-full lg:w-64"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleRealDataConsult()}
            />
            <button onClick={() => handleRealDataConsult()} className="bg-slate-900 text-white px-6 py-2 rounded-xl font-black text-xs hover:bg-slate-800 transition-all">INVESTIGAR</button>
          </div>
        </header>

        {currentView === 'lead_scan' ? (
          <div className="space-y-8 max-w-7xl mx-auto">
             <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50">
               <div className="flex items-center gap-4 mb-8">
                  <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-100">
                    <DatabaseZap size={28} />
                  </div>
                  <div>
                    <h2 className="text-2xl font-black text-slate-900">Minerador Estratégico de Leads</h2>
                    <p className="text-slate-500 text-sm font-medium">Sincronizando diretórios e Google Meu Negócio para contatos válidos.</p>
                  </div>
               </div>

               <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-6 gap-4 mb-8">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">UF</label>
                    <input type="text" placeholder="Ex: SP" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.uf} onChange={e => setLeadParams({...leadParams, uf: e.target.value})} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">Cidade</label>
                    <input type="text" placeholder="Ex: São Paulo" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.city} onChange={e => setLeadParams({...leadParams, city: e.target.value})} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">CNAE / Setor</label>
                    <input type="text" placeholder="Ex: Softwares" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.cnae} onChange={e => setLeadParams({...leadParams, cnae: e.target.value})} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">Cap. Social Min.</label>
                    <input type="text" placeholder="Ex: 100.000" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.minCapital} onChange={e => setLeadParams({...leadParams, minCapital: e.target.value})} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">CEP Ref.</label>
                    <input type="text" placeholder="00000-000" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.cep} onChange={e => setLeadParams({...leadParams, cep: e.target.value})} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-2">Qtd</label>
                    <input type="number" className="w-full bg-slate-50 border border-slate-200 rounded-xl py-3 px-4 focus:ring-4 focus:ring-indigo-500/5 transition-all font-bold text-sm" value={leadParams.limit} onChange={e => setLeadParams({...leadParams, limit: parseInt(e.target.value) || 0})} />
                  </div>
               </div>

               <button 
                  onClick={handleLeadScan} 
                  disabled={isSearching} 
