import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Consulta de Auditoria Real e Processos Judiciais - MODO DOSSIÊ COMPLETO
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = `REALIZE UMA INVESTIGAÇÃO DE CAMPO DIGITAL PARA: ${query} (${identifier}).

    FONTES OBRIGATÓRIAS:
    1. JURÍDICO: Jusbrasil, Escavador, Diários Oficiais (Processos ativos/passivos).
    2. CADASTRAL: Casa dos Dados, Econodata, QSA Oficial, Portais de Transparência.
    3. SOCIAL: LinkedIn, Instagram, Facebook, Twitter/X (Contas vinculadas).
    4. REPUTAÇÃO: Reclame Aqui, Google Reviews, Notícias locais.

    ESTRUTURE O RELATÓRIO EXATAMENTE COM ESTAS MARCAÇÕES PARA O PARSER:

    #SECAO_RESUMO#
    [Resumo executivo de 3 linhas sobre a entidade]
    NÍVEL_DE_RISCO: [BAIXO | MÉDIO | ALTO]

    #SECAO_DADOS#
    [Dados principais: Fundação, Capital, Sócios, Endereço completo]

    #SECAO_JURIDICO#
    [Lista de processos encontrados ou 'Nenhum registro encontrado']

    #SECAO_SOCIAL#
    [Links e resumo da presença em redes sociais e pegada digital]

    #SECAO_NOTICIAS#
    [Citações recentes na mídia ou portais de notícias]

    REGRAS:
    - Seja extremamente factual.
    - Se encontrar processos, cite o tribunal.
    - Se encontrar redes sociais, descreva o volume de seguidores/atividade.
    - Detalhe o Capital Social e Sócios encontrados.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um analista de inteligência (OSINT). Seu objetivo é compilar um dossiê estruturado e visual a partir de dados reais da web brasileira.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return {
      text: response.text,
      sources: response.candidates?.[0]?.groundingMetadata?.groundingChunks || []
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura Avançada de Leads - MULTI-FONTE + ENRIQUECIMENTO VIA GOOGLE BUSINESS (GMN)
 */
export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number, minCapital?: string) => {
  try {
    const prompt = `ATUAR COMO MINERADOR DE LEADS B2B COM ENRIQUECIMENTO GOOGLE BUSINESS.
    OBJETIVO: Encontrar ${limit} empresas REAIS em ${city}/${uf} do setor ${cnae}.

    FONTES PRIMÁRIAS (MANTENHA E EXTRAIA DADOS DAQUI): 
    - casadosdados.com.br
    - econodata.com.br
    - cnpj.biz
    - empresasdobrasil.com

    NOVA DIRETRIZ CRÍTICA DE CONTATO:
    SE VOCÊ LOCALIZAR UMA EMPRESA NOS DIRETÓRIOS ACIMA MAS O TELEFONE ESTIVER "NÃO INFORMADO" OU OCULTO, VOCÊ DEVE OBRIGATORIAMENTE REALIZAR UMA BUSCA ADICIONAL NO "GOOGLE MEU NEGÓCIO / GOOGLE MAPS" PARA ESSA EMPRESA ESPECÍFICA.

    A missão é: Não entregar leads sem telefone se existir um perfil no Google Business com o contato.

    PARA CADA LEAD, EXTRAIA OBRIGATORIAMENTE:
    ---LEAD_START---
    FONTE_NOME: [Indique as fontes usadas, Ex: Casa dos Dados + Google Business]
    EMPRESA: [Nome da Empresa]
    CNPJ: [CNPJ]
    CIDADE: [Cidade/UF]
    SOCIOS: [Sócios]
    CAPITAL: [Capital Social]
    TELEFONES: [Telefones (Priorize o do Google Business se o do diretório for nulo)]
    FONTE: [Link do diretório principal]
    GMN: [Link do Perfil Google Business/Maps se encontrado]
    ATIVIDADE: [Atividade]
    ---LEAD_END---

    REGRAS:
    - Streaming via Gemini 3 Flash.
    - Se o telefone vier do Google Business, marque na FONTE_NOME.
    - Mantenha a integridade dos dados cadastrais dos diretórios (CNPJ, Sócios, Capital).`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um robô de prospecção estratégica. Se o dado de contato sumir em um diretório, sua obrigação é caçá-lo no Google Maps/Meu Negócio. Responda apenas com os blocos estruturados.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return responseStream;
  } catch (error) {
    console.error("Lead Stream Error:", error);
    throw error;
  }
};

