import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Consulta de Auditoria Real via Google Search Grounding
 * Extrai dados públicos, processos, reputação e presença digital.
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = `REALIZE UMA INVESTIGAÇÃO PROFUNDA VIA GOOGLE SEARCH PARA: ${query} (${identifier}).

    INSTRUÇÕES DE BUSCA:
    - Localize dados oficiais em portais como Casa dos Dados, Econodata, e CNPJ.biz.
    - Procure por processos judiciais no Jusbrasil e Escavador.
    - Verifique a reputação no Reclame Aqui e Google Reviews.
    - Identifique a presença digital (LinkedIn, Instagram, Site Oficial).

    ESTRUTURE O RELATÓRIO EXATAMENTE COM ESTAS MARCAÇÕES:

    #SECAO_RESUMO#
    [Resumo executivo da entidade com base nos achados recentes]
    NÍVEL_DE_RISCO: [BAIXO | MÉDIO | ALTO]

    #SECAO_DADOS#
    [Razão Social, Nome Fantasia, Capital Social, Data de Abertura, Sócios Administradores e Endereço Atualizado]

    #SECAO_JURIDICO#
    [Detalhes de processos encontrados, tribunais e natureza das ações (se houver)]

    #SECAO_SOCIAL#
    [Links e resumo da pegada digital encontrada no Google]

    #SECAO_NOTICIAS#
    [Menções recentes em notícias ou blogs corporativos]

    REGRAS:
    - Utilize apenas informações encontradas via busca.
    - Seja imparcial e factual.
    - Se for empresa, cruze os dados do CNPJ com o Google Meu Negócio.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um especialista em OSINT (Open Source Intelligence) focado no mercado brasileiro. Sua missão é transformar resultados de busca do Google em um dossiê estruturado.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    // Extração das fontes de grounding conforme as diretrizes do Google
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Fonte de Pesquisa',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return {
      text: response.text,
      sources: sources
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura Avançada de Leads com Enriquecimento
 */
export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number, minCapital?: string) => {
  try {
    const prompt = `MINERAÇÃO DE LEADS B2B: ${limit} empresas em ${city}/${uf}, setor ${cnae}.
    Use o Google para validar telefones via Google Business se os diretórios falharem.`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Extraia leads estruturados em blocos ---LEAD_START--- e ---LEAD_END---.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return responseStream;
  } catch (error) {
    console.error("Lead Stream Error:", error);
    throw error;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import CompanyCard from './components/CompanyCard';
import Dashboard from './components/Dashboard';
import FilterModal from './components/FilterModal';
import { Company, ViewType, FilterState, SearchMode, LeadScanParams, Lead } from './types';
import { MOCK_COMPANIES } from './mockData';
import { 
  Search, X, MapPin, Globe, ShieldCheck, Loader2, ArrowRight, DatabaseZap, Gavel, 
  User, Target, Briefcase, Users, Navigation, Phone, Info, Link2, Zap, 
  Scale, Share2, Newspaper, AlertTriangle, CheckCircle, FileText,
  Hash, Building2, Download, Coins, SearchCode, Store, Check, ExternalLink
} from 'lucide-react';
import { fetchPublicDataReport, scanCompaniesStream } from './services/geminiService';

const App: React.FC = () => {
  const [currentView, setView] = useState<ViewType>('dashboard');
  const [searchMode, setSearchMode] = useState<SearchMode>('CNPJ');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [leadParams, setLeadParams] = useState<LeadScanParams>({ 
    uf: '', city: '', cnae: '', cep: '', limit: 10, minCapital: ''
  });

  const [selectedItem, setSelectedItem] = useState<{name: string, identifier: string, type: 'EMPRESA' | 'PESSOA'} | null>(null);
  const [publicDataReport, setPublicDataReport] = useState<{text: string, sources: any[]} | null>(null);
  const [isSearching, setIsSearching] = useState(false);
  const [streamingText, setStreamingText] = useState('');
  const [leads, setLeads] = useState<Lead[]>([]);

  useEffect(() => {
    const leadBlocks = streamingText.split('---LEAD_START---').slice(1);
    const parsedLeads: Lead[] = leadBlocks.map(block => {
      const cleanBlock = block.split('---LEAD_END---')[0];
      const lines = cleanBlock.split('\n').map(l => l.trim()).filter(l => l !== '');
      const findValue = (key: string) => {
        const line = lines.find(l => l.toUpperCase().startsWith(key.toUpperCase()));
        return line ? line.substring(line.indexOf(':') + 1).trim() : '';
      };
      return {
        sourceName: findValue('FONTE_NOME') || 'Web Search',
        name: findValue('EMPRESA'),
        cnpj: findValue('CNPJ'),
        address: findValue('CIDADE'),
        partners: findValue('SOCIOS').split(',').map(s => s.trim()).filter(s => s),
        phones: findValue('TELEFONES').split(',').map(p => p.trim()).filter(p => p),
        googleBusinessLink: findValue('GMN'),
        sourceLink: findValue('FONTE'),
        activity: findValue('ATIVIDADE'),
        capitalSocial: findValue('CAPITAL')
      };
    }).filter(l => l.name);
    setLeads(parsedLeads);
  }, [streamingText]);

  const handleRealDataConsult = async (targetIdentifier?: string, targetName?: string) => {
    const query = targetIdentifier || targetName || searchTerm;
    if (!query || query.length < 3) return;
    const identifier = targetIdentifier || (searchMode !== 'NOME' ? query : 'Busca por Nome');
    const name = targetName || (searchMode === 'NOME' ? query : 'Investigação');
    const type = searchMode === 'CPF' ? 'PESSOA' : 'EMPRESA';
    setSelectedItem({ name, identifier, type });
    setPublicDataReport(null);
    setIsSearching(true);
    try {
      const result = await fetchPublicDataReport(identifier, query, type);
      setPublicDataReport(result);
    } catch (error) {
      alert("Erro ao realizar consulta no Google Search.");
    } finally { setIsSearching(false); }
  };

  const handleLeadScan = async () => {
    if (!leadParams.uf && !leadParams.city && !leadParams.cnae) return;
    setIsSearching(true);
    setStreamingText('');
    setLeads([]);
    try {
      const stream = await scanCompaniesStream(
        leadParams.uf, leadParams.city, leadParams.cnae, leadParams.cep, leadParams.limit, leadParams.minCapital
      );
      for await (const chunk of stream) {
        setStreamingText(prev => prev + chunk.text);
      }
    } catch (error) { alert("Erro na varredura."); } finally { setIsSearching(false); }
  };

  const parseDossie = (text: string) => {
    const sections = {
      resumo: text.split('#SECAO_RESUMO#')[1]?.split('#SECAO_DADOS#')[0] || '',
      dados: text.split('#SECAO_DADOS#')[1]?.split('#SECAO_JURIDICO#')[0] || '',
      juridico: text.split('#SECAO_JURIDICO#')[1]?.split('#SECAO_SOCIAL#')[0] || '',
      social: text.split('#SECAO_SOCIAL#')[1]?.split('#SECAO_NOTICIAS#')[0] || '',
      noticias: text.split('#SECAO_NOTICIAS#')[1] || ''
    };
    const risk = sections.resumo.includes('RISCO: ALTO') ? 'alto' : sections.resumo.includes('RISCO: MÉDIO') ? 'medio' : 'baixo';
    return { sections, risk };
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex text-slate-900 font-['Inter']">
      <Sidebar currentView={currentView} setView={setView} isOpen={isSidebarOpen} toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)} filters={{} as any} setFilters={() => {}} />

      <main className="flex-1 lg:ml-64 p-6 lg:p-12">
        <header className="mb-10 max-w-6xl mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div>
