import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Consulta de Auditoria Real via Google Search Grounding
 * Extrai dados públicos, processos, reputação e presença digital.
 */
export const fetchPublicDataReport = async (identifier: string, query: string, type: 'EMPRESA' | 'PESSOA' = 'EMPRESA') => {
  try {
    const prompt = `REALIZE UMA INVESTIGAÇÃO PROFUNDA VIA GOOGLE SEARCH PARA: ${query} (${identifier}).

    INSTRUÇÕES DE BUSCA:
    - Localize dados oficiais em portais como Casa dos Dados, Econodata, e CNPJ.biz.
    - Procure por processos judiciais no Jusbrasil e Escavador.
    - Verifique a reputação no Reclame Aqui e Google Reviews.
    - Identifique a presença digital (LinkedIn, Instagram, Site Oficial).

    ESTRUTURE O RELATÓRIO EXATAMENTE COM ESTAS MARCAÇÕES:

    #SECAO_RESUMO#
    [Resumo executivo da entidade com base nos achados recentes]
    NÍVEL_DE_RISCO: [BAIXO | MÉDIO | ALTO]

    #SECAO_DADOS#
    [Razão Social, Nome Fantasia, Capital Social, Data de Abertura, Sócios Administradores e Endereço Atualizado]

    #SECAO_JURIDICO#
    [Detalhes de processos encontrados, tribunais e natureza das ações (se houver)]

    #SECAO_SOCIAL#
    [Links e resumo da pegada digital encontrada no Google]

    #SECAO_NOTICIAS#
    [Menções recentes em notícias ou blogs corporativos]

    REGRAS:
    - Utilize apenas informações encontradas via busca.
    - Seja imparcial e factual.
    - Se for empresa, cruze os dados do CNPJ com o Google Meu Negócio.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Você é um especialista em OSINT (Open Source Intelligence) focado no mercado brasileiro. Sua missão é transformar resultados de busca do Google em um dossiê estruturado.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || 'Fonte de Pesquisa',
      uri: chunk.web?.uri
    })).filter((s: any) => s.uri) || [];

    return {
      text: response.text,
      sources: sources
    };
  } catch (error) {
    console.error("Audit Search Error:", error);
    throw error;
  }
};

/**
 * Varredura Avançada de Leads com Enriquecimento
 */
export const scanCompaniesStream = async (uf: string, city: string, cnae: string, cep: string, limit: number, minCapital?: string) => {
  try {
    const prompt = `MINERAÇÃO DE LEADS B2B: Encontre ${limit} empresas em ${city}/${uf}, setor ${cnae}.
    Use o Google para validar telefones via Google Business.`;

    const responseStream = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: "Extraia leads estruturados em blocos ---LEAD_START--- e ---LEAD_END---. Campos: EMPRESA, CNPJ, CIDADE, SOCIOS, CAPITAL, TELEFONES, FONTE, GMN, ATIVIDADE.",
        thinkingConfig: { thinkingBudget: 0 }
      }
    });

    return responseStream;
  } catch (error) {
